import { useState, useEffect } from "react";
import { saveProfile, getProfile } from "../services/api";

function Profile() {
  const userId = localStorage.getItem("user_id");

  const [age, setAge] = useState("");
  const [sex, setSex] = useState("");
  const [height, setHeight] = useState("");
  const [weight, setWeight] = useState("");

  useEffect(() => {
    if (userId) {
      getProfile(userId).then(res => {
        if (res.data) {
          setAge(res.data.age || "");
          setSex(res.data.sex || "");
          setHeight(res.data.height || "");
          setWeight(res.data.weight || "");
        }
      });
    }
  }, [userId]);

  const handleSave = async () => {
    try {
      await saveProfile({
        user_id: userId,
        age,
        sex,
        height,
        weight
      });
      alert("Profile saved successfully");
    } catch (err) {
      alert("Failed to save profile");
    }
  };

  return (
    <div>
      <h2>Update Profile</h2>

      <input placeholder="Age" value={age} onChange={e => setAge(e.target.value)} />
      <br />

      <input placeholder="Sex" value={sex} onChange={e => setSex(e.target.value)} />
      <br />

      <input placeholder="Height (cm)" value={height} onChange={e => setHeight(e.target.value)} />
      <br />

      <input placeholder="Weight (kg)" value={weight} onChange={e => setWeight(e.target.value)} />
      <br />

      <button onClick={handleSave}>Save Profile</button>
    </div>
  );
}

export default Profile;
